#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Analyzes mathematical operations on Product data using sqlgen
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create Product table if it doesn't exist
  const char* create_table_sql = R"(
    CREATE TABLE IF NOT EXISTS Product (
      product_id INTEGER PRIMARY KEY,
      name TEXT NOT NULL,
      price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL NOT NULL
    )
  )";
  auto create_result = conn->execute(create_table_sql);
  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  // 3. Insert products into the table
  auto write_result = sqlgen::write(conn, products);
  if (!write_result) {
    throw std::runtime_error("Failed to insert products");
  }

  // 4. Build and execute the mathematical analysis query
  auto query = sqlgen::select_from<Product>(
    "product_id"_c,
    "name"_c,
    sqlgen::abs("price"_c).as<"abs_price">(),
    sqlgen::ceil("price"_c).as<"ceil_price">(),
    sqlgen::floor("price"_c).as<"floor_price">(),
    sqlgen::round("price"_c, 2).as<"rounded_price">(),
    sqlgen::exp("discount_rate"_c / 100).as<"exp_discount">(),
    sqlgen::ln("price"_c).as<"ln_price">(),
    sqlgen::log2("quantity"_c).as<"log2_quantity">(),
    sqlgen::sin("discount_rate"_c).as<"sin_discount">(),
    sqlgen::cos("discount_rate"_c).as<"cos_discount">(),
    sqlgen::tan("discount_rate"_c).as<"tan_discount">(),
    sqlgen::sqrt("quantity"_c).as<"sqrt_quantity">()
  );

  // 5. Execute query and map results to MathAnalysis structure
  auto result = (query | sqlgen::to<std::vector<MathAnalysis>>)(conn);
  if (!result) {
    throw std::runtime_error("Failed to execute query");
  }

  return result.value();
}

}  // namespace mathematical_operations_analysis
