std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen::literals;

  // 1. Establish database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create update query with string replacement
  auto update_query = sqlgen::update<Note>(
      "content"_c.set(sqlgen::transpilation::replace("content"_c, "foo", "bar"))
  );

  // 3. Execute the update operation
  update_query(conn);

  // 4. Read the updated data
  auto read_query = sqlgen::read<std::vector<Note>>;
  auto notes_result = read_query(conn);

  // 5. Transform results to UpdatedNote structure
  std::vector<UpdatedNote> updated_notes;
  for (const auto& note : notes_result.value()) {
